function fmt(e){try{return typeof e==='string'?e:JSON.stringify(e).slice(0,300);}catch(_){return String(e);}}
// n02b · 自动 refresh 7 国 Shopee access_token（v2.3 新增）
// 每次 workflow 触发时第 0 步跑：
//   1. 从 cms-api 拉持久化的 refresh_tokens (fallback to env SHOPEE_REFRESH_TOKENS)
//   2. foreach 7 国调 /api/v2/auth/access_token/get refresh
//   3. 拿到新 access_token + 新 refresh_token（refresh_token 每次也会变！）
//   4. 把新 refresh_tokens 持久化回 cms-api (下次用)
//   5. access_tokens 通过节点跨引用传给 n14b 用
// Stub fallback: SHOPEE_PARTNER_KEY 未配 → 全 skip

const ctx = $input.first().json;
const http = this.helpers.httpRequest;
const crypto = require('crypto');

const partnerId = $env.SHOPEE_PARTNER_ID || '';
const partnerKey = $env.SHOPEE_PARTNER_KEY || '';
const apiBase = $env.SHOPEE_API_BASE || 'https://openplatform.shopee.sg';
let shopIds = {};
let envRefresh = {};
try { shopIds = JSON.parse($env.SHOPEE_SHOP_IDS || '{}'); } catch (e) {}
try { envRefresh = JSON.parse($env.SHOPEE_REFRESH_TOKENS || '{}'); } catch (e) {}

const markets = JSON.parse(ctx.market_list || '[]');

if (!partnerId || !partnerKey) {
  return [{ json: { ...ctx, access_tokens: {}, refresh_status: 'stub_no_shopee_credentials' }}];
}

// 1. 拿持久化 refresh_tokens (fallback env)
let refreshTokens = {};
try {
  const stored = await http({
    method: 'GET', url: 'http://cms-api:8789/api/automation/shopee/tokens',
    json: true, timeout: 10000
  });
  refreshTokens = (stored && stored.refresh_tokens) || {};
} catch (e) {}
// 合并：cms-api 有的优先，env 兜底
for (const mk of markets) {
  if (!refreshTokens[mk] && envRefresh[mk]) refreshTokens[mk] = envRefresh[mk];
}



// 2. foreach refresh
const newAccess = {};
const newRefresh = {};
const errors = [];
const path = '/api/v2/auth/access_token/get';
for (const mk of markets) {
  const shopId = shopIds[mk];
  const refreshToken = refreshTokens[mk];
  if (!shopId || !refreshToken) {
    errors.push({ mk, reason: 'no shop_id or refresh_token (env/KV 都没)' });
    continue;
  }
  const ts = Math.floor(Date.now() / 1000);
  const baseString = `${partnerId}${path}${ts}`;
  const sign = crypto.createHmac('sha256', partnerKey).update(baseString).digest('hex');
  const url = `${apiBase}${path}?partner_id=${partnerId}&timestamp=${ts}&sign=${sign}`;
  try {
    const resp = await http({
      method: 'POST', url,
      headers: { 'Content-Type': 'application/json' },
      body: { refresh_token: refreshToken, shop_id: Number(shopId), partner_id: Number(partnerId) },
      json: true, timeout: 30000
    });
    if (resp && resp.error) {
      errors.push({ mk, reason: `${resp.error}: ${(resp.message || '').slice(0,120)}` });
    } else if (resp && resp.access_token) {
      newAccess[mk] = resp.access_token;
      newRefresh[mk] = resp.refresh_token || refreshToken;
    } else {
      errors.push({ mk, reason: 'no access_token in response' });
    }
  } catch (e) {
    errors.push({ mk, reason: fmt(e) });
  }
}

// 3. 持久化新 refresh_tokens
if (Object.keys(newRefresh).length > 0) {
  try {
    // merge：保留 env 但本次新的覆盖
    const merged = { ...envRefresh, ...refreshTokens, ...newRefresh };
    await http({
      method: 'PUT', url: 'http://cms-api:8789/api/automation/shopee/tokens',
      headers: { 'Content-Type': 'application/json' },
      body: { refresh_tokens: merged, updated_at: new Date().toISOString() },
      json: true, timeout: 10000
    });
  } catch (e) {
    errors.push({ stage: 'persist', reason: fmt(e) });
  }
}

const okCount = Object.keys(newAccess).length;
const total = markets.length;
const status = okCount === total ? 'all_ok' : okCount === 0 ? 'all_failed' : 'partial';

return [{ json: { ...ctx, access_tokens: newAccess, refresh_errors: errors, refresh_status: status }}];

