// B2 · SPU 聚合（按 Boss 预指定 spu_groups 分组 SKU）
// 类目不再硬编码 CAT_MAP — 改由 n14b 调 Shopee category_recommend API 自动判定
// 输入: B1 返回的 SKU 主档数组 + 原 webhook payload 的 spu_groups
// 输出: [{ spu_key, sku_list, markets, _vars }]

const vars = $('变量提取').item.json;
const skuList = $input.all().map(i => i.json);
const spuGroups = JSON.parse(vars.spu_groups_json || '[]');
const markets = JSON.parse(vars.market_list);

function firstCatTag(tags) {
  if (!Array.isArray(tags)) return null;
  return tags.find(t => typeof t === 'string' && t.startsWith('cat-')) || null;
}

// SPU 分组：Boss 给了 spu_groups 就用，没给就退化到 1 SKU = 1 SPU
let groups;
if (spuGroups.length > 0) {
  groups = spuGroups.map(g => ({
    spu_key: g.spu_key,
    sku_list: skuList.filter(s => g.sku_jans.includes(s.jan || s.sku))
  })).filter(g => g.sku_list.length > 0);
} else {
  groups = skuList.map(s => ({ spu_key: s.jan || s.sku, sku_list: [s] }));
}

return groups.map(g => ({
  json: {
    spu_key: g.spu_key,
    sku_count: g.sku_list.length,
    sku_list: g.sku_list,
    // Shopify 内部 cat tag（信息性，仅用于 fallback 显示，不参与 Shopee 上架）
    cat_tag_shopify: firstCatTag(g.sku_list[0]?.tags),
    markets: markets,
    _vars: vars,
    llm_input_json: JSON.stringify({spu_key: g.spu_key, sku_list: g.sku_list})
  }
}));

// B3 · 调火山方舟 DeepSeek（jsCode 版，绕开 jsonBody 表达式坑）
const ctx = $('B2 · SPU 聚合').first().json;
const item = $input.first().json;
const http = this.helpers.httpRequest;

const body = {
  model: ctx._vars.volc_ark_model || 'deepseek-v3-2-251201',
  messages: [
    {
      role: 'system',
      content: '你是 Shopee 跨境上架内容专家。给你 N 个 SKU 的中/日文标题和卖点，请输出 1 个 SPU 的完整上架内容。严格按 JSON schema 返回，不要 markdown 围栏，不要解释文字。Schema: { spu_title_zh: string(<=30字), spu_desc_zh: string(200-400字), spu_seo: { keywords: array, tag: array, meta_desc: string }, translations: { TW: {title, desc}, PH: {title, desc}, MY: {title, desc}, SG: {title, desc}, TH: {title, desc}, VN: {title, desc}, BR: {title, desc} } }。每国 title <= 60 字，desc 200-400 字。TW/SG 繁体中文；PH 英语；MY 马来语；TH 泰语；VN 越南语；BR 葡萄牙语。'
    },
    {
      role: 'user',
      content: item.llm_input_json
    }
  ],
  response_format: { type: 'json_object' },
  temperature: 0.3
};

const url = ctx._vars.volc_ark_url || 'https://ark.cn-beijing.volces.com/api/v3/chat/completions';
const apiKey = ctx._vars.volc_ark_api_key || $env.VOLC_ARK_API_KEY || '';

if (!apiKey) {
  return [{ json: { _llm_skip: 'no_api_key', choices: [{ message: { content: '{}' } }] } }];
}

try {
  const resp = await http({
    method: 'POST', url,
    headers: { 'Content-Type': 'application/json', 'Authorization': 'Bearer ' + apiKey },
    body, json: true, timeout: 60000
  });
  return [{ json: resp }];
} catch (e) {
  return [{ json: { _llm_error: String(e).slice(0, 500), choices: [{ message: { content: '{}' } }] } }];
}

// B3.2 · 解析 LLM JSON 输出，挂回 SPU 上下文
const llmResp = $input.first().json;
const spuCtx = $('SPU 循环 · 每次 1 个').item.json;

let content = null;
try {
  const choice = llmResp.choices?.[0]?.message?.content;
  if (typeof choice === 'string') {
    // 去掉可能的 ```json 围栏
    const cleaned = choice.replace(/^```(?:json)?\s*/, '').replace(/\s*```$/, '').trim();
    content = JSON.parse(cleaned);
  } else if (choice && typeof choice === 'object') {
    content = choice;
  }
} catch (e) {
  content = { _parse_error: String(e), _raw: llmResp.choices?.[0]?.message?.content };
}

return [{
  json: {
    ...spuCtx,
    llm_content: content,
    llm_ok: !!(content && content.spu_title_zh && content.translations)
  }
}];

// B3.5 · Shopee category_recommend（自动判定各国类目）
// 对 ctx.markets 里每个国家调用 Shopee Open API /api/v2/product/category_recommend
// 输入: B3.2 产出的 ctx.llm_content.translations[mk].title 作为 item_name
// access_tokens 跨节点引用 n02b 的输出（每次 workflow 触发时刚 refresh 的）
// 输出: ctx.cat_per_market = { TW: 12345, PH: 67890, ... }
//
// 凭证 fallback：若 SHOPEE_PARTNER_KEY 未设 → 整节点 skip，cat_per_market 全 null
// 这样 workflow 在 Shopee 凭证齐全前仍可端到端跑通（XLSX category_id 列空）

const ctx = $input.first().json;
const http = this.helpers.httpRequest;
const crypto = require('crypto');

const partnerId = $env.SHOPEE_PARTNER_ID || '';
const partnerKey = $env.SHOPEE_PARTNER_KEY || '';
const apiBase = $env.SHOPEE_API_BASE || 'https://openplatform.shopee.sg';
let shopIds = {};
try { shopIds = JSON.parse($env.SHOPEE_SHOP_IDS || '{}'); } catch (e) {}
// access_tokens 来自 n02b 节点（刚刚 refresh 完，永远新鲜）
const accessTokens = $('n02b · Shopee token 自动 refresh').first().json.access_tokens || {};

const markets = ctx.markets || [];
const translations = ctx.llm_content?.translations || {};
const results = {};
const errors = [];

if (!partnerId || !partnerKey) {
  // 凭证未配 → 整节点 stub
  for (const mk of markets) results[mk] = null;
  return [{
    json: {
      ...ctx,
      cat_per_market: results,
      category_status: 'stub_no_shopee_credentials'
    }
  }];
}

const path = '/api/v2/product/category_recommend';
const timestamp = Math.floor(Date.now() / 1000);

for (const mk of markets) {
  const shopId = shopIds[mk];
  const accessToken = accessTokens[mk];
  const itemName = translations[mk]?.title;
  if (!shopId || !accessToken) {
    results[mk] = null;
    errors.push({ mk, reason: `no shop_id/access_token in env for ${mk}` });
    continue;
  }
  if (!itemName) {
    results[mk] = null;
    errors.push({ mk, reason: 'no LLM translation for this market' });
    continue;
  }
  // Shopee HMAC-SHA256 sign: base = partner_id + path + timestamp + access_token + shop_id
  const baseString = `${partnerId}${path}${timestamp}${accessToken}${shopId}`;
  const sign = crypto.createHmac('sha256', partnerKey).update(baseString).digest('hex');
  const url = `${apiBase}${path}?partner_id=${partnerId}&timestamp=${timestamp}&access_token=${accessToken}&shop_id=${shopId}&sign=${sign}`;
  try {
    const resp = await http({
      method: 'POST', url,
      headers: { 'Content-Type': 'application/json' },
      body: { item_name: itemName },
      json: true, timeout: 30000
    });
    if (resp && resp.error) {
      results[mk] = null;
      errors.push({ mk, reason: `${resp.error}: ${(resp.message || '').slice(0, 100)}` });
    } else {
      // Shopee 返回 response.category_id_list 是数组（top N 推荐）
      const cats = resp?.response?.category_id_list || [];
      results[mk] = cats[0] || null;
    }
  } catch (e) {
    results[mk] = null;
    errors.push({ mk, reason: String(e).slice(0, 200) });
  }
}

const okCount = Object.values(results).filter(v => v).length;
let status;
if (okCount === markets.length) status = 'all_ok';
else if (okCount === 0) status = 'all_failed';
else status = 'partial';

return [{
  json: {
    ...ctx,
    cat_per_market: results,
    category_errors: errors,
    category_status: status
  }
}];

function fmt(e){try{return typeof e==='string'?e:JSON.stringify(e).slice(0,300);}catch(_){return String(e);}}
// B4 · 主图流水线（串行调 image-processor sidecar）
// 对每个 SKU 跑 upscale → cutout，最后对整个 SPU 跑 compose-spu
// 注：N8N Code node 没法 await fetch（v1.x 限制），用 node-fetch 同步样式
const ctx = $input.first().json;
const base = ctx._vars.image_processor_base;
const skuList = ctx.sku_list;

// 用 N8N 内置 helpers.httpRequest（typeVersion 2 Code node 支持）
const http = this.helpers.httpRequest;

const results = { upscale: [], cutout: [], spu_image: null, errors: [] };

// Step 1: foreach SKU upscale + cutout
for (const sku of skuList) {
  const jan = sku.jan || sku.sku;
  const imgUrl = sku.main_image_url || sku.image_url || sku.image;
  if (!jan || !imgUrl) {
    results.errors.push({ jan, reason: 'no jan or image_url in SKU master' });
    continue;
  }
  try {
    const up = await http({
      method: 'POST', url: base + '/upscale',
      headers: { 'Content-Type': 'application/json' },
      body: { jan, image_url: imgUrl, method: 'lanczos' },
      json: true, timeout: 60000
    });
    results.upscale.push(up);
    const cut = await http({
      method: 'POST', url: base + '/cutout',
      headers: { 'Content-Type': 'application/json' },
      body: { jan },
      json: true, timeout: 120000
    });
    results.cutout.push(cut);
  } catch (e) {
    results.errors.push({ jan, reason: fmt(e) });
  }
}

// Step 2: 1 次 compose-spu 拼接
if (results.cutout.length > 0) {
  try {
    const spu = await http({
      method: 'POST', url: base + '/compose-spu',
      headers: { 'Content-Type': 'application/json' },
      body: { spu_key: ctx.spu_key, sku_jans: results.cutout.map(c => c.jan), source: 'branded' },
      json: true, timeout: 60000
    });
    results.spu_image = spu;
  } catch (e) {
    results.errors.push({ stage: 'compose-spu', reason: fmt(e) });
  }
}

return [{
  json: {
    ...ctx,
    image_results: results,
    image_ok: !!(results.spu_image && results.spu_image.saved_path) && results.errors.length === 0
  }
}];

// B5a · 拼装 XLSX 行（每 SPU 1 行；7 国并列字段）
// 输出结构对应 Shopee 通用上架表 simplified 版
const ctx = $input.first().json;
const tr = ctx.llm_content?.translations || {};
const row = {
  spu_key: ctx.spu_key,
  sku_count: ctx.sku_count,
  cat_tag_shopify: ctx.cat_tag_shopify || '',
  category_status: ctx.category_status || 'unknown',
  spu_title_zh: ctx.llm_content?.spu_title_zh || '',
  spu_desc_zh: ctx.llm_content?.spu_desc_zh || '',
  seo_keywords: (ctx.llm_content?.spu_seo?.keywords || []).join('|'),
  seo_tag: (ctx.llm_content?.spu_seo?.tag || []).join('|'),
  seo_meta_desc: ctx.llm_content?.spu_seo?.meta_desc || '',
  main_image_path: ctx.image_results?.spu_image?.saved_path || '',
  sku_jans: ctx.sku_list.map(s => s.jan || s.sku).join(','),
};
for (const mk of ctx.markets) {
  row[`title_${mk}`] = tr[mk]?.title || '';
  row[`desc_${mk}`]  = tr[mk]?.desc || '';
  row[`category_id_${mk}`] = ctx.cat_per_market?.[mk] || '';
}
return [{ json: row }];

// B5c · Shopee 上架（stub，等 Partner Key）
// TODO 接 Shopee Open API:
//   1. POST /api/v2/product/add_item per market
//   2. POST /api/v2/product/upload_image
//   3. 解析 item_id，写回 CMS
// 当前: 直接透传 + 占位
const rows = $input.all().map(i => i.json);
return [{
  json: {
    rows_processed: rows.length,
    shopee_status: 'STUB · 等 Partner Key',
    spu_keys: rows.map(r => r.spu_key)
  }
}];

// 汇总：从所有 SPU 处理结果统计 → 给 CMS 回调和飞书用
const rows = $('B5c · Shopee 上架（stub）').first().json;
const vars = $('变量提取').first().json;

const allRows = $items('B5a · 拼 XLSX 行').map(i => i.json);
const llmOk = allRows.filter(r => r.spu_title_zh).length;
const imageOk = allRows.filter(r => r.main_image_path).length;
// 类目: 看 category_status all_ok / partial / stub_no_shopee_credentials
const catAllOk = allRows.filter(r => r.category_status === 'all_ok').length;
const catPartial = allRows.filter(r => r.category_status === 'partial').length;
const catStub = allRows.filter(r => r.category_status === 'stub_no_shopee_credentials').length;
const catFailed = allRows.filter(r => r.category_status === 'all_failed').length;

let catSummary;
if (catStub === allRows.length) catSummary = '⏸ STUB（等 Shopee 凭证）';
else catSummary = `✅ ${catAllOk}/${allRows.length} 全市场 OK · ⚠️ ${catPartial} 部分 · ❌ ${catFailed} 失败`;

return [{
  json: {
    run_id: vars.run_id,
    cms_callback: vars.cms_callback,
    summary: {
      total_spu: allRows.length,
      llm_ok: llmOk,
      image_ok: imageOk,
      category: catSummary,
      shopee: rows.shopee_status
    }
  }
}];

// 飞书签名计算（HMAC-SHA256）— $env 驱动
// 配置：.env 里 LARK_BOT_SIGN_SECRET=xxx + LARK_WEBHOOK_URL=https://...
// 校验失败 19021 通常 = secret 跟飞书 bot 后台不一致 → 飞书后台「安全设置」复制 secret 重配 .env
const crypto = require('crypto');
const secret = $env.LARK_BOT_SIGN_SECRET || '';
const url = $env.LARK_WEBHOOK_URL || '';
const now = Math.floor(Date.now() / 1000);
let ts = '', sign = '';
if (secret) {
  const stringToSign = `${now}\n${secret}`;
  const hmac = crypto.createHmac('sha256', stringToSign);
  hmac.update('');
  sign = hmac.digest('base64');
  ts = String(now);
}
const prev = $input.first().json;
return [{ json: { ...prev, lark_timestamp: ts, lark_sign: sign, _lark_webhook_url: url } }];

